const fmt = (n,c="") => {if(!n&&n!==0)return"-";const s=typeof n==="number"?n.toLocaleString("ru-RU",{minimumFractionDigits:0,maximumFractionDigits:2}):""+n;return c?s+" "+c:s};

const Badge = ({t,children}) => {
  const cl = {active:"bg-blue-100 text-blue-700",completed:"bg-green-100 text-green-700",domestic:"bg-gray-100 text-gray-700",export:"bg-purple-100 text-purple-700",debt:"bg-red-100 text-red-700",closed:"bg-green-100 text-green-700"};
  return <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${cl[t]||"bg-gray-100"}`}>{children}</span>;
};

const Modal = ({open,onClose,title,children}) => {
  if(!open) return null;
  return <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={onClose}>
    <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg mx-4 max-h-[80vh] overflow-auto" onClick={e=>e.stopPropagation()}>
      <div className="flex items-center justify-between p-4 border-b"><h3 className="text-lg font-bold">{title}</h3>
        <button onClick={onClose} className="text-gray-400 hover:text-gray-600 text-xl">&times;</button></div>
      <div className="p-4">{children}</div></div></div>;
};

const Inp = ({label,value,onChange,type="text"}) => (
  <div><label className="block text-sm font-medium text-gray-600 mb-1">{label}</label>
    <input type={type} value={value||""} onChange={e=>onChange(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"/></div>
);

const Btn = ({children,onClick,v="primary",disabled=false,className=""}) => {
  const s = v==="primary"?"bg-blue-600 text-white hover:bg-blue-700":v==="danger"?"bg-red-600 text-white hover:bg-red-700":"bg-gray-100 text-gray-700 hover:bg-gray-200";
  return <button onClick={onClick} disabled={disabled} className={`px-4 py-2 rounded-lg text-sm font-medium transition ${s} ${disabled?"opacity-50 cursor-not-allowed":""} ${className}`}>{children}</button>;
};

